from typing import Callable, Any
from beeai.tools import Tool

import bleach

class SecureTool(Tool):
    def __init__(self, original_tool: Tool, allowed_tags=None):
        self.original_tool = original_tool
        self.allowed_tags = allowed_tags or []

    async def call(self, **kwargs) -> Any:
        # Sanitize all string inputs
        sanitized_kwargs = {}
        for k, v in kwargs.items():
            if isinstance(v, str):
                sanitized_kwargs[k] = bleach.clean(v, tags=self.allowed_tags)
            else:
                sanitized_kwargs[k] = v

        # Length limits
        for k, v in sanitized_kwargs.items():
            if isinstance(v, str) and len(v) > 1000:
                raise ValueError(f'Input too long: {k}')

        return await self.original_tool.call(**sanitized_kwargs)

# Wrap existing tools
